// // This module is designed to shift right on the rising edge of the clock and has an active-high synchronous reset signal.
module shift_reg3bit (
    input wire clk,
    input wire rstn,
    input wire d,
    output reg [2:0] q
);

always @(posedge clk or negedge rstn)
begin
    if (~rstn)
        q <= 3'b000;
    else
        q <= {q[1:0], d};
end

endmodule
